import sys
from collections import defaultdict

def main():
    input = sys.stdin.read
    data = input().splitlines()
    friends = data[0].strip()[2:-2].replace('"', '').split(', ')
    gifts = data[1].strip()[2:-2].replace('"', '').split(', ')

    gift_count = defaultdict(lambda: defaultdict(int))
    for gift in gifts:
        giver, receiver = gift.split()
        gift_count[giver][receiver] += 1

    gift_index = defaultdict(int)
    for giver in friends:
        total_given = sum(gift_count[giver].values())
        total_received = sum(gift_count[receiver][giver] for receiver in friends)
        gift_index[giver] = total_given - total_received

    received_gifts = defaultdict(int)
    for giver in friends:
        for receiver in friends:
            if giver == receiver:
                continue
            if gift_count[giver][receiver] > gift_count[receiver][giver]:
                received_gifts[receiver] += 1
            elif gift_count[giver][receiver] < gift_count[receiver][giver]:
                received_gifts[giver] += 1
            else:
                if gift_index[giver] > gift_index[receiver]:
                    received_gifts[receiver] += 1
                elif gift_index[giver] < gift_index[receiver]:
                    received_gifts[giver] += 1
                # 선물 지수가 같은 경우는 아무도 받지 않음
                elif gift_index[giver] == gift_index[receiver]:
                    continue

    max_gifts = max(received_gifts.values(), default=0)
    print(max_gifts)

if __name__ == '__main__':
    main()

